python3 - <<'PY'
from pathlib import Path

skip = {Path('notes/user.txt'), Path('.git')}
for path in sorted(Path('.').rglob('*')):
    if path.is_dir() or any(part == '.git' for part in path.parts):
        continue
    if path in skip:
        continue
    data = path.read_bytes()
    if b'\0' in data:
        continue
    try:
        text = data.decode('utf-8')
    except UnicodeDecodeError:
        continue
    text = text.replace('\r\n', '\n').replace('\r', '\n')
    lines = text.split('\n')
    # If the file ended in a newline, split leaves a final empty sentinel.
    if lines and lines[-1] == '':
        body = lines[:-1]
    else:
        body = lines
    normalized = '\n'.join(line.rstrip() for line in body)
    if normalized or text:
        normalized += '\n'
    new = normalized.encode('utf-8')
    if new != data:
        path.write_bytes(new)
PY
